// V4.3: 参数校验 + 智能跳过(基于anchor) + 增量锚点
const task = $input.first().json;
const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (!dateRegex.test(task.month_start) || !dateRegex.test(task.month_end)) {
  throw new Error('日期格式异常: ' + task.month_start + ' / ' + task.month_end);
}
if (!['SO','PO','WO','TR'].includes(task.doc_type)) {
  throw new Error('未知单据类型: ' + task.doc_type);
}

const prevCount = Number(task.prev_row_count || 0);
const anchorDate = task.anchor_date || null;

// 智能跳过条件:
// 1. 历史月份 (month_end < 本月1号)
// 2. 有 last_anchor_date (说明之前成功同步过且有数据)
// 注: last_anchor_date 不被 wf20-xx 启动器重置，安全可靠
// 注: 空月(无数据)没有 anchor，会重查 SAP 但秒级返回
const today = new Date();
const monthFirst = new Date(today.getFullYear(), today.getMonth(), 1);
const monthEnd = new Date(task.month_end);
const isHistorical = monthEnd < monthFirst;
const canSkip = isHistorical && anchorDate !== null;

// 增量锚点: 当月有锚点时从锚点开始查，缩小 SAP 查询范围
const effectiveStart = (!canSkip && anchorDate) ? anchorDate : task.month_start;

return { json: {
  task_id: task.id, doc_type: task.doc_type,
  month_start: task.month_start, month_end: task.month_end,
  company_code: task.company_code,
  skip_sap: canSkip,
  effective_start: effectiveStart,
  anchor_date: anchorDate,
  is_historical: isHistorical,
  prev_row_count: prevCount,
  start_ts: Date.now()
}};

// V4.1: 生成分批 UPSERT SQL — 防旧覆盖 + 领空保护 + sync_status + 批量(500行)
const taskNode = $('参数校验').first().json;
const companyCode = taskNode.company_code;
const rows = $input.all().map(r => r.json);
const validRows = rows.filter(r => r.doc_type && r.sap_doc_entry);

if (validRows.length === 0) {
  return [{ json: { skip: true, task_id: taskNode.task_id, count: 0, message: '无SAP数据', sap_rows: 0 } }];
}

const orderMap = new Map();
validRows.forEach(r => {
  const key = `${r.doc_type}_${r.sap_doc_entry}`;
  if (!orderMap.has(key)) {
    orderMap.set(key, {
      doc_type: r.doc_type, sap_doc_entry: r.sap_doc_entry, sap_doc_num: String(r.sap_doc_num),
      business_partner: r.business_partner || '', bp_name: r.bp_name || '',
      doc_date: r.doc_date || null, due_date: r.due_date || null,
      sap_status: r.sap_status || 'O', sap_cancelled: r.sap_cancelled || 'N',
      doc_total: r.doc_total || 0, doc_currency: r.doc_currency || '',
      sap_update_date: r.sap_update_date || null, sap_update_time: r.sap_update_time || '00:00:00',
      header_item_code: r.header_item_code || null, header_item_name: r.header_item_name || null,
      header_planned_qty: r.header_planned_qty != null ? r.header_planned_qty : null,
      header_actual_qty: r.header_actual_qty != null ? r.header_actual_qty : null,
      header_warehouse: r.header_warehouse || null,
      header_from_warehouse: r.header_from_warehouse || null,
      header_to_warehouse: r.header_to_warehouse || null,
      lines: []
    });
  }
  if (r.line_num !== null && r.line_num !== undefined) { orderMap.get(key).lines.push({
    line_num: r.line_num, item_code: r.item_code || '', item_name: r.item_name || '',
    quantity: r.quantity || 0, open_quantity: r.open_quantity || 0,
    delivered_qty: r.delivered_qty || 0, issued_qty: r.issued_qty || 0,
    warehouse_code: r.warehouse_code || '', uom: r.uom || '', ship_date: r.ship_date || null,
    from_warehouse: r.line_from_warehouse || null, item_type: r.item_type != null ? r.item_type : null,
    sap_update_date: r.sap_update_date || null,
    sap_update_time: r.sap_update_time || '00:00:00'
  }); }
});

const esc = (v) => String(v || '').replace(/'/g, "''");
const num = (v) => { const n = Number(v); return isNaN(n) ? 0 : n; };
const escOrNull = (v) => v === null || v === undefined ? 'NULL' : `'${esc(v)}'`;
const numOrNull = (v) => v === null || v === undefined ? 'NULL' : num(v);
const orders = Array.from(orderMap.values());

const batches = [];
let currentBatch = '';
let currentRows = 0;

orders.forEach(o => {
  const hashInput = `${o.sap_status}|${o.sap_cancelled}|${o.doc_total}|${o.business_partner}|${o.lines.length}|${o.header_item_code || ''}|${o.header_planned_qty != null ? o.header_planned_qty : ''}|${o.header_actual_qty != null ? o.header_actual_qty : ''}`;

  currentBatch += `\nINSERT INTO oms.orders (company_code, doc_type, doc_number, sap_doc_entry, sap_doc_num, business_partner, bp_name, doc_date, due_date, sap_status, sap_cancelled, doc_total, doc_currency, sap_update_date, sap_update_time, item_code, item_name, planned_qty, actual_qty, warehouse_code, from_warehouse, to_warehouse, expected_line_count, sync_status, sap_data_hash, sap_last_seen_at, oms_status) VALUES ('${esc(companyCode)}', '${esc(o.doc_type)}', '${esc(o.sap_doc_num)}', ${num(o.sap_doc_entry)}, '${esc(o.sap_doc_num)}', '${esc(o.business_partner)}', '${esc(o.bp_name)}', ${escOrNull(o.doc_date)}, ${escOrNull(o.due_date)}, '${esc(o.sap_status)}', '${esc(o.sap_cancelled)}', ${num(o.doc_total)}, '${esc(o.doc_currency)}', ${escOrNull(o.sap_update_date)}, ${escOrNull(o.sap_update_time)}, ${escOrNull(o.header_item_code)}, ${escOrNull(o.header_item_name)}, ${numOrNull(o.header_planned_qty)}, ${numOrNull(o.header_actual_qty)}, ${escOrNull(o.header_warehouse)}, ${escOrNull(o.header_from_warehouse)}, ${escOrNull(o.header_to_warehouse)}, ${o.lines.length}, 'syncing', MD5('${esc(hashInput)}'), NOW(), 'pending') ON CONFLICT (company_code, doc_type, sap_doc_entry) WHERE parent_id IS NULL AND sap_doc_entry IS NOT NULL DO UPDATE SET doc_number=EXCLUDED.doc_number, sap_doc_num=EXCLUDED.sap_doc_num, business_partner=EXCLUDED.business_partner, bp_name=EXCLUDED.bp_name, doc_date=EXCLUDED.doc_date, due_date=EXCLUDED.due_date, sap_status=EXCLUDED.sap_status, sap_cancelled=EXCLUDED.sap_cancelled, doc_total=EXCLUDED.doc_total, doc_currency=EXCLUDED.doc_currency, sap_update_date=EXCLUDED.sap_update_date, sap_update_time=EXCLUDED.sap_update_time, item_code=EXCLUDED.item_code, item_name=EXCLUDED.item_name, planned_qty=EXCLUDED.planned_qty, actual_qty=EXCLUDED.actual_qty, warehouse_code=COALESCE(EXCLUDED.warehouse_code, oms.orders.warehouse_code), from_warehouse=COALESCE(EXCLUDED.from_warehouse, oms.orders.from_warehouse), to_warehouse=COALESCE(EXCLUDED.to_warehouse, oms.orders.to_warehouse), expected_line_count=EXCLUDED.expected_line_count, sync_status='syncing', sap_data_hash=EXCLUDED.sap_data_hash, sap_last_seen_at=NOW(), oms_status=CASE WHEN oms.orders.oms_status IN ('split','executing') THEN oms.orders.oms_status WHEN EXCLUDED.sap_cancelled='Y' THEN 'cancelled' WHEN EXCLUDED.sap_status IN ('C','L') THEN 'completed' ELSE oms.orders.oms_status END, execution_state=CASE WHEN oms.orders.oms_status IN ('split') OR oms.orders.execution_state='executing' THEN oms.orders.execution_state WHEN EXCLUDED.sap_cancelled='Y' THEN 'done' WHEN EXCLUDED.sap_status IN ('C','L') THEN 'done' ELSE oms.orders.execution_state END;\n`;

  o.lines.forEach(ln => {
    const sud = escOrNull(ln.sap_update_date);
    const sut = escOrNull(ln.sap_update_time);
    currentBatch += `INSERT INTO oms.order_lines (order_id, company_code, line_num, item_code, item_name, quantity, open_quantity, delivered_qty, issued_qty, warehouse_code, from_warehouse, uom, ship_date, sap_update_date, sap_update_time, item_type) SELECT id, '${esc(companyCode)}', ${num(ln.line_num)}, '${esc(ln.item_code)}', '${esc(ln.item_name)}', ${num(ln.quantity)}, ${num(ln.open_quantity)}, ${num(ln.delivered_qty)}, ${num(ln.issued_qty)}, '${esc(ln.warehouse_code)}', ${escOrNull(ln.from_warehouse)}, '${esc(ln.uom)}', ${escOrNull(ln.ship_date)}, ${sud}, ${sut}, ${ln.item_type !== null && ln.item_type !== undefined ? ln.item_type : 'NULL'} FROM oms.orders WHERE company_code='${esc(companyCode)}' AND doc_type='${esc(o.doc_type)}' AND sap_doc_entry=${num(o.sap_doc_entry)} AND parent_id IS NULL ON CONFLICT (order_id, line_num) DO UPDATE SET item_code=CASE WHEN (EXCLUDED.sap_update_date, EXCLUDED.sap_update_time)>=(oms.order_lines.sap_update_date, oms.order_lines.sap_update_time) OR oms.order_lines.sap_update_date IS NULL THEN EXCLUDED.item_code ELSE oms.order_lines.item_code END, item_name=CASE WHEN (EXCLUDED.sap_update_date, EXCLUDED.sap_update_time)>=(oms.order_lines.sap_update_date, oms.order_lines.sap_update_time) OR oms.order_lines.sap_update_date IS NULL THEN EXCLUDED.item_name ELSE oms.order_lines.item_name END, quantity=CASE WHEN (EXCLUDED.sap_update_date, EXCLUDED.sap_update_time)>=(oms.order_lines.sap_update_date, oms.order_lines.sap_update_time) OR oms.order_lines.sap_update_date IS NULL THEN EXCLUDED.quantity ELSE oms.order_lines.quantity END, open_quantity=CASE WHEN (EXCLUDED.sap_update_date, EXCLUDED.sap_update_time)>=(oms.order_lines.sap_update_date, oms.order_lines.sap_update_time) OR oms.order_lines.sap_update_date IS NULL THEN EXCLUDED.open_quantity ELSE oms.order_lines.open_quantity END, delivered_qty=CASE WHEN (EXCLUDED.sap_update_date, EXCLUDED.sap_update_time)>=(oms.order_lines.sap_update_date, oms.order_lines.sap_update_time) OR oms.order_lines.sap_update_date IS NULL THEN EXCLUDED.delivered_qty ELSE oms.order_lines.delivered_qty END, issued_qty=CASE WHEN (EXCLUDED.sap_update_date, EXCLUDED.sap_update_time)>=(oms.order_lines.sap_update_date, oms.order_lines.sap_update_time) OR oms.order_lines.sap_update_date IS NULL THEN EXCLUDED.issued_qty ELSE oms.order_lines.issued_qty END, warehouse_code=EXCLUDED.warehouse_code, from_warehouse=COALESCE(EXCLUDED.from_warehouse, oms.order_lines.from_warehouse), uom=EXCLUDED.uom, ship_date=EXCLUDED.ship_date, sap_update_date=CASE WHEN (EXCLUDED.sap_update_date, EXCLUDED.sap_update_time)>=(oms.order_lines.sap_update_date, oms.order_lines.sap_update_time) OR oms.order_lines.sap_update_date IS NULL THEN EXCLUDED.sap_update_date ELSE oms.order_lines.sap_update_date END, sap_update_time=CASE WHEN (EXCLUDED.sap_update_date, EXCLUDED.sap_update_time)>=(oms.order_lines.sap_update_date, oms.order_lines.sap_update_time) OR oms.order_lines.sap_update_date IS NULL THEN EXCLUDED.sap_update_time ELSE oms.order_lines.sap_update_time END, item_type=EXCLUDED.item_type;\n`;
    currentRows++;
  });
  currentRows++;

  if (currentRows >= 500) {
    batches.push({ json: { sql: currentBatch, batch_rows: currentRows, task_id: taskNode.task_id } });
    currentBatch = ''; currentRows = 0;
  }
});

if (currentBatch) {
  batches.push({ json: { sql: currentBatch, batch_rows: currentRows, task_id: taskNode.task_id } });
}

if (batches.length > 0) {
  batches[batches.length - 1].json.total_orders = orders.length;
  batches[batches.length - 1].json.sap_rows = validRows.length;
}

return batches.length > 0 ? batches : [{ json: { skip: true, task_id: taskNode.task_id, count: 0, sap_rows: 0 } }];

// V4.0: 汇总 + 透明化上下文
const taskNode = $('参数校验').first().json;
const allItems = $('生成UPSERT SQL').all();
let totalOrders = 0;
let totalSapRows = 0;
let totalBatches = allItems.length;
allItems.forEach(item => {
  totalOrders += (item.json.total_orders || 0);
  totalSapRows += (item.json.sap_rows || 0);
});
const elapsedMs = Date.now() - (taskNode.start_ts || Date.now());
const context = JSON.stringify({
  orders: totalOrders,
  sap_rows: totalSapRows,
  batches: totalBatches,
  elapsed_ms: elapsedMs,
  effective_start: taskNode.effective_start,
  month_range: taskNode.month_start + ' ~ ' + taskNode.month_end,
  anchor_used: taskNode.effective_start !== taskNode.month_start,
  ts: new Date().toISOString()
});
const validateSql = `UPDATE oms.orders o SET sync_status = CASE WHEN o.expected_line_count IS NOT NULL AND o.expected_line_count = (SELECT COUNT(*) FROM oms.order_lines WHERE order_id = o.id) THEN 'complete' WHEN o.expected_line_count IS NULL THEN 'complete' ELSE 'error' END WHERE o.company_code = current_setting('app.company_code') AND o.sync_status = 'syncing'; INSERT INTO oms.wms_alerts (company_code, alert_type, severity, source, message, context) SELECT o.company_code, 'SYNC_LINE_MISMATCH', 'warning', 'wf20a', 'Order ' || o.doc_type || ' ' || o.sap_doc_num || ': expected ' || o.expected_line_count || ' lines, got ' || cnt.actual, jsonb_build_object('order_id', o.id, 'doc_type', o.doc_type, 'expected', o.expected_line_count, 'actual', cnt.actual) FROM oms.orders o CROSS JOIN LATERAL (SELECT COUNT(*) AS actual FROM oms.order_lines WHERE order_id = o.id) cnt WHERE o.company_code = current_setting('app.company_code') AND o.sync_status = 'error' AND o.expected_line_count IS DISTINCT FROM cnt.actual AND NOT EXISTS (SELECT 1 FROM oms.wms_alerts a WHERE a.context->>'order_id' = o.id::text AND a.alert_type = 'SYNC_LINE_MISMATCH' AND a.created_at > NOW() - INTERVAL '1 hour');`;
return { json: { task_id: taskNode.task_id, count: totalOrders, success: true, validate_sql: validateSql, context: context } };

let taskId = null;
try { taskId = $('原子领取').first().json.id; } catch(e) {}
const errorMsg = ($input.first().json.error && $input.first().json.error.message) || 'Unknown error';
return { json: { task_id: taskId, error_message: String(errorMsg).substring(0, 500) } };

// 未知的 doc_type，记录告警
const item = $input.first();
const docType = item.json.doc_type || 'unknown';
console.log('Unknown doc_type: ' + docType);
return [{ json: { skip: true, reason: 'unknown_doc_type', doc_type: docType } }];
